  ('dietitian-moex-10577', 'dietitian', 'dietitian-moex-094-cd594556', 'sub-dietitian-03', NULL, 'single_choice', '下列有關ketogenesis之敘述何者為非？', '["leucine是唯一只具ketogenic功能的胺基酸", "ketogenic amino acid經catabolism後以acetyl CoA去產生ketone bodies", "ketogenesis之產物之一的acetone不能為細胞所利用", "ketogenesis易於carbohydrate和lipid攝取不足時發生"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:56+00:00", "source_pdf_sha1": "2b924a8f44c2", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "094130", "c": "112", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "營養學", "year": "094", "exam_name": "094年第二次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 3, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
